import java.io.*;
  import sailpoint.tools.Util;
  import java.io.IOException;


  if("account".equalsIgnoreCase(schema.getNativeObjectType())){

 // String accountFile =stats.get("absolutePath");

    String accountFile = application.getAttributes().get("file");

log.error("file path from application obj.."+accountFile);

		File directory = new File(accountFile);
		File chosenFile = null;

		SimpleDateFormat sdf = new SimpleDateFormat("yyyyMMdd");
		Date latestDate = null;
		File latestFile = null;
    String latestRedData;
    BufferedInputStream bis =null;

		if (directory.isDirectory()) {

			File[] files = directory.listFiles();
			for (File file : files) {

				String fileName = file.getName();
				String fileDateString = fileName.substring(11, fileName.indexOf("."));

				// My file name pattern is like  CF_TestData22-08-2025.csv

				String datePart = fileName.substring(11, fileName.lastIndexOf("."));
				log.error("date Part substring  : " + datePart);

				Date fileDate = null;
				try {
					fileDate = sdf.parse(datePart);
				} catch (ParseException e) {

					log.error("date error "+e.getMessage());
				}

				if (latestDate == null || fileDate.after(latestDate)) {

					latestDate = fileDate;
					latestFile = file;
				}
			}

			if (latestFile != null) {

        try{
				 latestRedData = readData(latestFile);

        }catch(IOException e){

         log.error(e.getMessage());

        }

				 bis = new BufferedInputStream(new ByteArrayInputStream(latestRedData.getBytes()));
				log.error("MAIN...\n" + latestRedData);
			}
		}



	private  String readData(File file) throws IOException {
		String line;
		String data = "";
		BufferedReader br = new BufferedReader(new FileReader(file));
		br.readLine();

		while ((line = br.readLine()) != null) {

			data += line + "\n";

			log.error("line .....\n " + line);
			log.error(" data ......\n " + data);
		}

		return data;
	}




  return bis ;
 }
